import React from 'react';

const PlaylistManager = ({ tracks, playlists, setPlaylists, currentTrackId, onTogglePlay }) => {
    const playlistNames = Object.keys(playlists);

    const addToFavorites = (trackId) => {
        if (!playlists['Favorites'].includes(trackId)) {
            setPlaylists({
                ...playlists,
                'Favorites': [...playlists['Favorites'], trackId]
            });
        }
    };

    return (
        <div>
            <h2>Мои плейлисты</h2>
            {playlistNames.length === 0 ? (
                <p>У вас пока нет плейлистов.</p>
            ) : (
                playlistNames.map(playlistName => (
                    <div key={playlistName} className="playlist-section">
                        <h3>{playlistName}</h3>
                        <div className="track-list compact">
                            {playlists[playlistName].map(trackId => {
                                const track = tracks.find(t => t.id === trackId);
                                if (!track) return null; // На случай, если трек удален
                                return (
                                    <div key={track.id} className="track-item compact">
                                        <span>{track.title} — {track.artist}</span>
                                        <button onClick={() => onTogglePlay(track.id)} className="icon-btn">
                                            {currentTrackId === track.id ? '⏸️' : '▶️'}
                                        </button>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                ))
            )}
            {/* Кнопка для демонстрации добавления (в реальном приложении тут был бы другой функционал) */}
            <div className="view-header">
                <h3>Быстрое добавление</h3>
                {tracks.length > 0 && (
                    <button onClick={() => addToFavorites(tracks[0].id)}>
                        ⭐ Добавить первый трек в «Favorites»
                    </button>
                )}
            </div>
        </div>
    );
};

export default PlaylistManager;
